arguments.command:
cd /tmp/sv-9d58dde16572461da9a5ef7266dc6ca4/symbols

# Get more detail for the two SGen worker addresses using nm on the debug file
nm test__.debug 2>/dev/null | sort | awk -v t1=$((0x2f4b20)) -v t2=$((0x2f4c84)) -v t3=$((0x2c1a40)) '
{
  addr = strtonum("0x" $1)
  if (addr <= t1) { n1=$3; a1=addr }
  if (addr <= t2) { n2=$3; a2=addr }
  if (addr <= t3) { n3=$3; a3=addr }
}
END {
  printf "0x2f4b20 -> %s+0x%x\n", n1, t1-a1
  printf "0x2f4c84 -> %s+0x%x\n", n2, t2-a2
  printf "0x2c1a40 -> %s+0x%x\n", n3, t3-a3
}'

